import { NextResponse } from 'next/server';
import { headers } from 'next/headers';
import { UserService } from '@/services/user.service';
import { signAccessToken, signRefreshToken } from '@/lib/auth';
import { rateLimit } from '@/lib/rate-limit';
import { prisma } from '@/lib/prisma';

export async function POST(request: Request) {
  try {
    // ── Rate Limiting ──────────────────────────────────────
    const headersList = await headers();
    const forwarded = headersList.get('x-forwarded-for');
    const ip = forwarded ? forwarded.split(',')[0].trim() : 'unknown';
    const limiter = rateLimit(`login_${ip}`, 5, 15 * 60); // 5 attempts per 15 mins

    if (!limiter.success) {
      return NextResponse.json({ 
        error: `Too many login attempts. Please try again in ${Math.ceil(limiter.retryAfterSeconds / 60)} minute(s).` 
      }, { status: 429 });
    }

    const { email, password } = await request.json();

    if (!email || !password) {
      return NextResponse.json({ error: 'Email and password are required' }, { status: 400 });
    }

    // 1. Find user
    const user = await UserService.findByEmail(email);
    if (!user) {
      return NextResponse.json({ error: 'Invalid credentials' }, { status: 401 });
    }

    // 2. Check verification
    if (!user.isVerified && email !== 'admin@cyrotics.in') {
      return NextResponse.json({ error: 'Please verify your email before logging in.' }, { status: 403 });
    }

    // 3. Verify password
    const isPasswordValid = await UserService.verifyPassword(password, user.passwordHash);
    if (!isPasswordValid) {
      return NextResponse.json({ error: 'Invalid credentials' }, { status: 401 });
    }

    // 4. Generate Tokens
    const payload = {
      userId: user.id,
      email: user.email,
      role: user.role
    };

    const accessToken = await signAccessToken(payload);
    const refreshToken = await signRefreshToken(payload);

    // 5. Store Refresh Token in DB
    await prisma.refreshToken.create({
      data: {
        token: refreshToken,
        userId: user.id,
        expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000), // 7 days
      },
    });

    // 6. Set Cookies
    const response = NextResponse.json({ 
      success: true,
      accessToken,
      user: { id: user.id, email: user.email, name: user.name, role: user.role }
    });

    response.cookies.set({
      name: 'refresh_token',
      value: refreshToken,
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      path: '/',
      maxAge: 7 * 24 * 60 * 60, // 7 days
    });

    // Optional: Also set access_token in cookie for easier server-side access
    response.cookies.set({
      name: 'access_token',
      value: accessToken,
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      path: '/',
      maxAge: 15 * 60, // 15 mins
    });

    return response;

  } catch (error) {
    console.error('[Login Error]', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  }
}
